function connection(online,detail='Giao diện vẫn dùng được độc lập'){state.apiOnline=online;if(online)state.everOnline=true;$('sideDot').classList.toggle('online',online);$('mobileDot').classList.toggle('online',online);$('sideConn').textContent=online?'Đã kết nối ESP32':'Chế độ cục bộ';$('sideDetail').textContent=detail;$('mobileConnText').textContent=online?'ESP32':'Cục bộ';renderDevice()}
function collectAll(){const c=state.config;c.deviceName=$('deviceName').value.trim()||c.deviceName;c.mainWebUrl=$('mainWebUrl').value.trim().replace(/\/$/,'');c.timezone=$('timezone').value;c.wifiSsid=$('wifiManual').value.trim()||$('wifiSsid').value||c.wifiSsid;c.eggType=$('eggType').value;c.batchName=$('batchName').value.trim();c.startDate=$('startDate').value;c.totalDays=n('totalDays');c.targetHumidity=n('targetHumidity');c.targetTemp=n('tempTarget');c.highAlarm=n('highAlarm');c.lowAlarm=n('lowAlarm');c.emergencyTemp=n('emergencyTemp');c.ventOn=n('ventOn');c.ventOff=n('ventOff');c.maxPower=n('maxPower');c.tempOffset=n('tempOffset');c.kp=n('kp');c.ki=n('ki');c.kd=n('kd');c.pidCycle=n('pidCycle');c.turningEnabled=$('turningEnabled').checked;c.turnInterval=n('turnInterval');c.limitAlarmTime=n('limitAlarmTime');c.nextDirection=$('nextDirection').value;c.humidityOffset=n('humidityOffset');c.sensorTimeout=n('sensorTimeout');c.cloudEnabled=$('cloudEnabled').checked;c.pwaUrl=$('pwaUrl').value.trim();c.workerUrl=$('workerUrl').value.trim().replace(/\/$/,'');c.cloudOfflineMinutes=n('cloudOfflineMinutes');c.cloudEmergency=$('cloudEmergency').checked;c.cloudSensor=$('cloudSensor').checked;c.cloudTurn=$('cloudTurn').checked;c.cloudOffline=$('cloudOffline').checked;if($('cloudDeviceKey').value.trim())c.cloudHasDeviceKey=true;return c}
function payload(){const c=collectAll();return{deviceName:c.deviceName,mainWebUrl:c.mainWebUrl,timezone:c.timezone,wifiSsid:c.wifiSsid,wifiPassword:$('wifiPassword').value,eggType:c.eggType,batchName:c.batchName,startDate:c.startDate,totalDays:c.totalDays,targetHumidity:c.targetHumidity,targetTemp:c.targetTemp,highAlarm:c.highAlarm,lowAlarm:c.lowAlarm,ventOn:c.ventOn,ventOff:c.ventOff,emergencyTemp:c.emergencyTemp,maxPower:c.maxPower,kp:c.kp,ki:c.ki,kd:c.kd,pidCycle:c.pidCycle,tempOffset:c.tempOffset,turningEnabled:c.turningEnabled?'1':'0',turnInterval:c.turnInterval,limitAlarmTime:c.limitAlarmTime,nextDirection:c.nextDirection,humidityOffset:c.humidityOffset,sensorTimeout:c.sensorTimeout,cloudEnabled:c.cloudEnabled?'1':'0',pwaUrl:c.pwaUrl,workerUrl:c.workerUrl,cloudDeviceKey:$('cloudDeviceKey').value,cloudOfflineMinutes:c.cloudOfflineMinutes,cloudEmergency:c.cloudEmergency?'1':'0',cloudSensor:c.cloudSensor?'1':'0',cloudTurn:c.cloudTurn?'1':'0',cloudOffline:c.cloudOffline?'1':'0'}}
async function saveAll(label='Đã lưu cấu hình'){collectAll();const err=validateFields();if(err){toast(err,'error');return false}saveLocal();if(state.apiOnline){try{await post('/api/config',payload(),6000);toast(label+' vào ESP32.');$('wifiPassword').value='';$('cloudDeviceKey').value='';await loadSelected()}catch{toast('Đã lưu trên trình duyệt nhưng ESP32 không phản hồi.','warn')}}else toast(label+' trên trình duyệt.');setDirty(false);fill();return true}
async function loadSelected(forceLocal=false){try{const data=await api('/api/bootstrap',{},3000,forceLocal);state.config={...defaults,...data.config};state.status={...clone(defaultStatus),...data.status,inputs:{...defaultStatus.inputs,...data.status?.inputs},outputs:{...defaultStatus.outputs,...data.status?.outputs}};if(forceLocal){state.hostDevice=data.device;state.selectedId=data.device.id}else if(!state.selectedId)state.selectedId=data.device.id;mergeDevice(data.device);connection(true,(data.device.name||data.device.id)+' · '+(data.device.ip||'cùng mạng'));saveLocal();fill();return true}catch{connection(false);state.config=loadLocal();fill();return false}}
async function loadDeviceById(id){state.selectedId=id;saveDevices();state.config=loadLocal();fill();const d=state.devices.find(x=>x.id===id);if(!d?.ip||state.hostDevice?.id===id){await loadSelected(true);return}connection(false,'Đang kết nối '+d.ip);try{const data=await api('/api/bootstrap',{},3000);state.config={...defaults,...data.config};state.status={...clone(defaultStatus),...data.status,inputs:{...defaultStatus.inputs,...data.status?.inputs},outputs:{...defaultStatus.outputs,...data.status?.outputs}};mergeDevice(data.device);connection(true,d.name+' · '+d.ip);saveLocal();fill()}catch{connection(false,d.name+' đang ngoại tuyến');toast('Không kết nối được '+d.name+'. Dữ liệu cục bộ vẫn sử dụng được.','warn')}}
function page(name){document.querySelectorAll('.page').forEach(x=>x.classList.toggle('active',x.id==='page-'+name));document.querySelectorAll('.nav button').forEach(x=>x.classList.toggle('active',x.dataset.page===name));$('pageTitle').textContent=pageMeta[name][0];$('pageSub').textContent=pageMeta[name][1];scrollTo(0,0)}
async function poll(){try{const d=await api('/api/status',{},1600);state.status={...state.status,...d,inputs:{...state.status.inputs,...d.inputs},outputs:{...state.status.outputs,...d.outputs}};if(!state.apiOnline)connection(true,'ESP32 đã kết nối lại');renderStatus();if(d.autotune)renderTune(d.autotune)}catch{if(state.apiOnline)connection(false,'ESP32 tạm thời không phản hồi')}}
function renderTune(t){state.tune={...state.tune,...t};$('tuneState').textContent=t.running?'Đang chạy':t.result?'Hoàn tất':'Sẵn sàng';$('tuneTemp').textContent=Number(t.temperature??state.status.temperature).toFixed(1)+'°C';$('tunePower').textContent=Math.round(t.heaterPower||0)+'%';$('tunePercent').textContent=Math.round(t.progress||0)+'%';$('tuneBar').style.width=(t.progress||0)+'%';$('startTune').classList.toggle('hidden',!!t.running);$('stopTune').classList.toggle('hidden',!t.running);$('tuneResult').classList.toggle('hidden',!t.result);$('applyTune').classList.toggle('hidden',!t.result);if(t.result){$('tuneKp').textContent=t.result.kp;$('tuneKi').textContent=t.result.ki;$('tuneKd').textContent=t.result.kd}}
function localTune(){clearInterval(state.tune.localTimer);state.tune.running=true;state.tune.progress=0;state.tune.localTimer=setInterval(()=>{state.tune.progress+=5;const p=state.tune.progress;renderTune({running:p<100,progress:p,temperature:state.status.temperature+Math.sin(p/10)*.25,heaterPower:p%20<10?100:0,result:p>=100?{kp:17.8,ki:.76,kd:47.2}:null});if(p>=100)clearInterval(state.tune.localTimer)},450)}
function renderTest(){const box=$('testSteps');box.innerHTML=tests.map((t,i)=>`<div class="testStep ${i===state.test.index?'active':''} ${state.test.results[i]||''}">${i+1}. ${t[1]}</div>`).join('')}
async function runTestStep(){if(state.test.index>=tests.length){state.test.running=false;$('testIndex').textContent='HOÀN TẤT';$('testTitle').textContent='Đã kiểm tra xong';$('testDesc').textContent='Xem trạng thái từng bước ở bên trái.';document.querySelectorAll('[data-answer]').forEach(b=>b.classList.add('hidden'));$('startSystemTest').classList.remove('hidden');renderTest();return}const [key,title,desc]=tests[state.test.index];$('testIndex').textContent='BƯỚC '+(state.test.index+1)+' / '+tests.length;$('testTitle').textContent=title;$('testDesc').textContent=desc;$('startSystemTest').classList.add('hidden');document.querySelectorAll('[data-answer]').forEach(b=>b.classList.remove('hidden'));renderTest();if(key!=='sensor')await setOutput(key,true,true)}
async function setOutput(name,value,quiet=false){if(Date.now()>state.maintenanceUntil){if(!quiet)toast('Hãy mở chế độ kiểm tra trước.','warn');return false}if(state.apiOnline){try{const d=await post('/api/output',{output:name,value:value?'1':'0'},2500);if(d.outputs)state.status.outputs={...state.status.outputs,...d.outputs};renderStatus();return true}catch{if(!quiet)toast('ESP32 từ chối hoặc không phản hồi.','error');return false}}state.status.outputs[name]=value;if(name==='motorLeft'&&value)state.status.outputs.motorRight=false;if(name==='motorRight'&&value)state.status.outputs.motorLeft=false;renderStatus();if(value)setTimeout(()=>{state.status.outputs[name]=false;renderStatus()},3000);return true}
async function discover(){const b=$('discoverDevices');b.disabled=true;b.textContent='Đang dò…';try{let list=[];if(state.apiOnline){const d=await api('/api/devices/discover',{},4500);list=d.devices||[]}else list=[{id:'MAP-A1B2',name:'Máy ấp trứng 01',ip:'192.168.1.81',online:true,firmware:'1.2.0'},{id:'MAP-C3D4',name:'Máy ấp trứng 02',ip:'192.168.1.82',online:true,firmware:'1.2.0'}];list.forEach(mergeDevice);toast('Đã cập nhật '+list.length+' thiết bị.')}catch{toast('Không dò được máy cùng mạng.','warn')}finally{b.disabled=false;b.textContent='Dò máy cùng mạng';renderDevice()}}
function confirmBox(title,text,confirm='Xác nhận'){return new Promise(resolve=>{const d=$('dialog');$('dialogTitle').textContent=title;$('dialogText').textContent=text;$('dialogConfirm').textContent=confirm;d.showModal();d.querySelectorAll('button').forEach(b=>b.onclick=()=>{d.close();resolve(b.value==='confirm')})})}

function setBadge(id,on){const e=$(id);if(!e)return;e.classList.toggle('on',!!on);e.classList.toggle('off',!on)}
function renderMachineBanner(){const b=$('machineBanner');if(!b)return;const st=state.status;let type='',icon='✓',title=state.config.batchRunning?'Đang ấp ổn định':'Máy sẵn sàng',detail=state.config.batchRunning?`Nhiệt độ đặt ${Number(state.config.targetTemp).toFixed(1)}°C · đảo mỗi ${state.config.turnInterval} phút`:'Chưa bắt đầu mẻ ấp.';if(st.turnFault){type='danger';icon='!';title='LỖI ĐẢO TRỨNG';detail=st.turnFaultMessage||'Không nhận công tắc hành trình trong thời gian cảnh báo.'}else if(!st.sensorOnline){type='danger';icon='!';title='MẤT TÍN HIỆU CẢM BIẾN';detail='Thanh nhiệt phải được khóa cho đến khi cảm biến ổn định.'}else if(Number(st.temperature)>=Number(state.config.emergencyTemp)){type='danger';icon='!';title='NHIỆT ĐỘ NGẮT KHẨN CẤP';detail='Thanh nhiệt đã được yêu cầu ngắt và quạt thông gió phải chạy.'}else if(Number(st.temperature)>=Number(state.config.highAlarm)){type='warning';icon='!';title='Nhiệt độ đang cao';detail=`Hiện tại ${Number(st.temperature).toFixed(1)}°C · cảnh báo ${Number(state.config.highAlarm).toFixed(1)}°C`}else if(!state.apiOnline){type='warning';icon='↯';title='Đang dùng dữ liệu cục bộ';detail='ESP32 chưa phản hồi; thay đổi vẫn có thể soạn nhưng chưa xác nhận trên máy.'}b.className='machineBanner '+type;$('bannerIcon').textContent=icon;$('bannerTitle').textContent=title;$('bannerDetail').textContent=detail}
function renderBatchSummary(){const names={chicken:'Trứng gà',duck:'Trứng vịt',quail:'Trứng cút',custom:'Tùy chỉnh'};$('sumEgg').textContent=names[$('eggType').value]||'Tùy chỉnh';$('sumDays').textContent=(Number($('totalDays').value)||0)+' ngày';$('sumTemp').textContent=(Number($('batchTarget').value)||0).toFixed(1)+'°C';$('sumHum').textContent=(Number($('targetHumidity').value)||0)+'%RH';$('sumTurn').textContent=(Number($('quickTurn').value)||0)+' phút'}
function validateFields(){collectAll();const c=state.config;const rules=[['highAlarmField',c.highAlarm>c.targetTemp],['emergencyField',c.emergencyTemp>=c.highAlarm+.5],['ventOnField',c.ventOn>c.ventOff&&c.ventOn<c.emergencyTemp]];rules.forEach(([id,ok])=>$(id)?.classList.toggle('invalid',!ok));const err=validate(c);$('validationBanner').textContent=err;$('validationBanner').classList.toggle('show',!!err);return err}
function setDirty(value=true){state.dirty=value;$('dirtyBar').classList.toggle('show',value);if(value)validateFields()}
function applyTechnicalMode(value){state.technical=!!value;document.querySelectorAll('.techOnly').forEach(e=>{e.classList.toggle('techHidden',!state.technical);if(!state.technical&&e.tagName==='DETAILS')e.open=false});$('modeUser').classList.toggle('active',!state.technical);$('modeTech').classList.toggle('active',state.technical);$('modeUser').setAttribute('aria-pressed',String(!state.technical));$('modeTech').setAttribute('aria-pressed',String(state.technical));$('settingsMode').classList.toggle('techActive',state.technical);$('modeState').textContent=state.technical?'KỸ THUẬT ĐÃ MỞ':'NGƯỜI DÙNG';$('modeDescription').textContent=state.technical?'Đang hiện PID, Auto Tune, I/O và hiệu chỉnh chuyên sâu.':'Chỉ hiện các cài đặt cần thiết để vận hành.'}
async function turnCommand(action){state.turnQueue=state.turnQueue.then(async()=>{try{if(state.apiOnline){const d=await post('/api/turn',{action},2500);if(d.config){state.config.turningEnabled=!!d.config.turningEnabled;if(d.config.nextDirection)state.config.nextDirection=d.config.nextDirection}if(d.outputs)state.status.outputs={...state.status.outputs,...d.outputs}}else{if(action==='auto'){state.config.turningEnabled=true;state.status.outputs.motorLeft=false;state.status.outputs.motorRight=false}else if(action==='stop'){state.status.outputs.motorLeft=false;state.status.outputs.motorRight=false}else if(action==='left'){if(state.status.inputs.limitLeft)throw Error('limit');state.config.turningEnabled=false;state.status.outputs.motorRight=false;state.status.outputs.motorLeft=true}else if(action==='right'){if(state.status.inputs.limitRight)throw Error('limit');state.config.turningEnabled=false;state.status.outputs.motorLeft=false;state.status.outputs.motorRight=true}saveLocal()}checked('turningEnabled',state.config.turningEnabled);renderStatus();}catch(e){renderStatus();toast(e.message==='limit'?'Đã chạm công tắc giới hạn.':'Không thực hiện được lệnh đảo.','error')}});return state.turnQueue}
function bindHoldTurn(button,action){let active=false;const start=e=>{e.preventDefault();if(button.disabled)return;active=true;button.classList.add('holding');button.setPointerCapture?.(e.pointerId);turnCommand(action)};const stop=e=>{if(!active)return;active=false;button.classList.remove('holding');turnCommand('stop')};button.addEventListener('pointerdown',start);['pointerup','pointercancel','lostpointercapture','pointerleave'].forEach(x=>button.addEventListener(x,stop));button.addEventListener('contextmenu',e=>e.preventDefault())}
function bindHoldStart(){const b=$('startBatch');let timer=null,tick=null,startAt=0;const cancel=()=>{clearTimeout(timer);clearInterval(tick);timer=tick=null;b.classList.remove('holding');b.style.setProperty('--hold-progress','0%')};b.addEventListener('pointerdown',e=>{e.preventDefault();if(state.config.batchRunning)return toast('Mẻ ấp đang hoạt động.','warn');startAt=Date.now();b.classList.add('holding');tick=setInterval(()=>b.style.setProperty('--hold-progress',Math.min(100,(Date.now()-startAt)/12)+'%'),40);timer=setTimeout(async()=>{cancel();await startBatchConfirmed()},1200)});['pointerup','pointercancel','pointerleave','lostpointercapture'].forEach(x=>b.addEventListener(x,cancel));b.addEventListener('click',e=>e.preventDefault())}
async function startBatchConfirmed(){collectAll();const err=validate();if(err)return toast(err,'error');const text=`${$('sumEgg').textContent} · ${$('sumDays').textContent} · ${$('sumTemp').textContent} · đảo mỗi ${$('sumTurn').textContent}.`;if(await confirmBox('Bắt đầu mẻ ấp',text,'Bắt đầu')){state.config.batchRunning=true;if(state.apiOnline)try{await post('/api/batch',{action:'start'})}catch{}saveLocal();setDirty(false);fill();toast('Đã bắt đầu mẻ ấp.')}}
function updateMaintenanceUi(){const left=Math.max(0,state.maintenanceUntil-Date.now()),active=left>0;$('maintenanceBanner').classList.toggle('show',active);if(active){const sec=Math.ceil(left/1000);$('maintenanceCountdown').textContent=String(Math.floor(sec/60)).padStart(2,'0')+':'+String(sec%60).padStart(2,'0')}else{$('maintenanceCountdown').textContent='00:00'}}
function showCriticalAlert(title,text,key=''){state.criticalKey=key;$('criticalTitle').textContent=title;$('criticalText').textContent=text;$('criticalAlert').classList.add('show');navigator.vibrate?.([250,120,250])}
function clearCriticalAlert(){$('criticalAlert').classList.remove('show');state.criticalKey=''}
function triggerAlert(key,title,text){if(state.alertState[key])return;state.alertState[key]=true;showCriticalAlert(title,text,key)}
function clearAlertState(key){state.alertState[key]=false;if(state.criticalKey===key)clearCriticalAlert()}
function monitorCriticalEvents(){const st=state.status,emergency=Number(st.temperature)>=Number(state.config.emergencyTemp);if(emergency)triggerAlert('emergency','NHIỆT ĐỘ NGẮT KHẨN CẤP',`Máy ${state.config.deviceName}: ${Number(st.temperature).toFixed(1)}°C. Thanh nhiệt phải ngắt ngay.`);else clearAlertState('emergency');if(!st.sensorOnline)triggerAlert('sensor','MẤT TÍN HIỆU CẢM BIẾN',`Máy ${state.config.deviceName} không nhận được dữ liệu nhiệt độ/độ ẩm.`);else clearAlertState('sensor');if(st.turnFault)triggerAlert('turn','LỖI ĐẢO TRỨNG',st.turnFaultMessage||'Không nhận công tắc hành trình đúng thời gian.');else clearAlertState('turn')}
function renderCloudStatus(){const c=state.config,configured=!!(c.cloudEnabled&&c.workerUrl&&c.pwaUrl&&c.cloudHasDeviceKey);$('cloudStatus').textContent=configured?'ĐÃ CẤU HÌNH':c.cloudEnabled?'THIẾU THÔNG TIN':'ĐANG TẮT';$('cloudStatus').className='pill '+(configured?'success':c.cloudEnabled?'warning':'neutral');$('cloudHelp').textContent=configured?'ESP32 sẽ gửi cảnh báo và heartbeat tới Worker bằng HTTPS.':c.cloudEnabled?'Cần Worker URL, PWA URL và khóa thiết bị.':'Bật kênh Cloudflare để nhận cảnh báo khi đã đóng giao diện cục bộ.';$('cloudKeyState').textContent=c.cloudHasDeviceKey?'ESP32 đã lưu khóa thiết bị; để trống nếu không thay đổi.':'Chưa có khóa trên ESP32.'}
function formatUptime(sec){sec=Number(sec)||0;const d=Math.floor(sec/86400),h=Math.floor(sec%86400/3600),m=Math.floor(sec%3600/60);return d?`${d} ngày ${h} giờ`:`${h} giờ ${m} phút`}
function renderSystemInfo(){const d=state.devices.find(x=>x.id===state.selectedId)||state.hostDevice||{};$('sysName').textContent=d.name||state.config.deviceName;$('sysDeviceId').textContent=d.id||'MAP-DEMO';$('sysModel').textContent=d.model||'Máy ấp ESP32-S3';$('sysFirmware').textContent=d.firmware||'1.4.0';$('sysWebUi').textContent=d.webUi||'1.4.0';$('sysChip').textContent=(d.chipModel||'ESP32-S3')+(d.chipRevision!==undefined?' rev '+d.chipRevision:'');$('sysCpu').textContent=(d.cpuMhz||240)+' MHz';$('sysFlash').textContent=(d.flashMb||16)+' MB';$('sysHeap').textContent=d.freeHeapKb!==undefined?d.freeHeapKb+' KB':'—';$('sysUptime').textContent=d.uptimeSec!==undefined?formatUptime(d.uptimeSec):'—';$('sysSdk').textContent=d.sdkVersion||'—'}
function randomCloudKey(){const bytes=new Uint8Array(24);crypto.getRandomValues(bytes);return Array.from(bytes,b=>b.toString(16).padStart(2,'0')).join('')}
async function enrollCloudDevice(){collectAll();const err=validate();if(err)return toast(err,'error');const setupCode=$('cloudSetupCode').value.trim(),deviceKey=$('cloudDeviceKey').value.trim();if(!setupCode)return toast('Cần nhập mã cài đặt Worker.','warn');if(!deviceKey&&!state.config.cloudHasDeviceKey)return toast('Cần tạo khóa thiết bị trước.','warn');if(!state.apiOnline){state.config.cloudHasDeviceKey=true;renderCloudStatus();return toast('Bản xem trước: đã mô phỏng đăng ký Worker.')}try{const d=await post('/api/cloud/enroll',{setupCode,deviceKey},10000);state.config.cloudHasDeviceKey=!!d.enrolled;$('cloudSetupCode').value='';$('cloudDeviceKey').value='';renderCloudStatus();toast('Đã đăng ký thiết bị với Cloudflare Worker.')}catch{toast('Không đăng ký được Worker. Kiểm tra Wi-Fi, URL và mã cài đặt.','error')}}
async function testCloudAlert(){if(!state.config.cloudEnabled)return toast('Hãy bật và lưu cấu hình Cloudflare trước.','warn');if(!state.apiOnline){showCriticalAlert('THÔNG BÁO THỬ CLOUDFLARE','Bản xem trước đã mô phỏng yêu cầu gửi Web Push.','cloud-test');return}try{await post('/api/cloud/test',{},10000);toast('Worker đã nhận yêu cầu cảnh báo thử.')}catch{toast('Không gửi được cảnh báo thử tới Worker.','error')}}
function openTechDialog(){if(state.technical)return;$('techPin').value='';$('techError').classList.remove('show');$('techDialog').showModal();setTimeout(()=>$('techPin').focus(),60)}
function confirmTechnicalMode(){if($('techPin').value==='2468'){$('techDialog').close();applyTechnicalMode(true);toast('Đã mở chế độ kỹ thuật.')}else{$('techError').classList.add('show');$('techPin').select()}}
function enhanceBind(){document.querySelectorAll('input,select').forEach(e=>{if(e.id==='wifiPassword'||e.classList.contains('browserSetting')||e.id==='techPin')return;e.addEventListener('input',()=>{setDirty(true);renderBatchSummary();if(e.id.startsWith('cloud')||e.id==='workerUrl'||e.id==='pwaUrl')renderCloudStatus()});e.addEventListener('change',()=>{setDirty(true);renderBatchSummary();if(e.id.startsWith('cloud')||e.id==='workerUrl'||e.id==='pwaUrl')renderCloudStatus()})});$('discardChanges').onclick=()=>{state.config=loadLocal();fill();setDirty(false);toast('Đã hủy các thay đổi chưa lưu.','warn')};$('saveChanges').onclick=()=>saveAll('Đã lưu tất cả thay đổi');$('modeUser').onclick=()=>{applyTechnicalMode(false);toast('Đã chuyển về chế độ người dùng.')};$('modeTech').onclick=openTechDialog;$('cancelTech').onclick=()=> $('techDialog').close();$('confirmTech').onclick=confirmTechnicalMode;$('techPin').addEventListener('keydown',e=>{if(e.key==='Enter')confirmTechnicalMode()});$('closeCritical').onclick=clearCriticalAlert;$('generateCloudKey').onclick=()=>{const key=randomCloudKey();$('cloudDeviceKey').value=key;state.config.cloudHasDeviceKey=true;setDirty(true);renderCloudStatus();toast('Đã tạo khóa riêng 48 ký tự cho thiết bị.')};$('enrollCloud').onclick=enrollCloudDevice;$('testCloud').onclick=testCloudAlert;$('openPwa').onclick=()=>{const u=$('pwaUrl').value.trim();if(!u)return toast('Chưa nhập địa chỉ PWA Cloudflare Pages.','warn');window.open(/push\.html(?:$|[?#])/.test(u)?u:u.replace(/\/?$/,'/push.html'),'_blank','noopener')};$('refreshSystem').onclick=async()=>{await loadSelected(state.hostDevice?.id===state.selectedId);renderSystemInfo();toast('Đã làm mới thông số máy.')};bindHoldTurn($('holdLeft'),'left');bindHoldTurn($('holdRight'),'right');$('turnStop').onclick=()=>turnCommand('stop');$('turnAuto').onclick=()=>turnCommand('auto');bindHoldStart();document.querySelectorAll('.settingsDetails').forEach(d=>d.addEventListener('toggle',()=>{if(d.open)document.querySelectorAll('.settingsDetails').forEach(x=>{if(x!==d)x.open=false})}));document.addEventListener('visibilitychange',()=>{if(document.hidden)turnCommand('stop')});window.addEventListener('blur',()=>turnCommand('stop'));applyTechnicalMode(false);renderBatchSummary();renderCloudStatus();renderSystemInfo();setInterval(updateMaintenanceUi,250)}
function bind(){document.querySelectorAll('.nav button').forEach(b=>b.onclick=()=>page(b.dataset.page));$('quickForm').onsubmit=async e=>{e.preventDefault();syncTarget(n('quickTarget'));syncTurn(n('quickTurn'));fill();await saveAll('Đã lưu thông số nhanh')};$('batchTarget').oninput=e=>syncTarget(e.target.value);$('tempTarget').oninput=e=>syncTarget(e.target.value);$('quickTarget').oninput=e=>syncTarget(e.target.value);$('turnInterval').oninput=e=>syncTurn(e.target.value);$('quickTurn').oninput=e=>syncTurn(e.target.value);$('batchForm').onsubmit=async e=>{e.preventDefault();syncTarget(n('batchTarget'));await saveAll('Đã lưu mẻ ấp')};$('temperatureForm').onsubmit=async e=>{e.preventDefault();syncTarget(n('tempTarget'));await saveAll('Đã lưu nhiệt độ và PID')};$('turningForm').onsubmit=async e=>{e.preventDefault();syncTurn(n('turnInterval'));await saveAll('Đã lưu cài đặt đảo')};$('connectionForm').onsubmit=async e=>{e.preventDefault();await saveAll('Đã lưu kết nối')};$('cloudForm').onsubmit=async e=>{e.preventDefault();await saveAll('Đã lưu cấu hình Cloudflare')};$('sensorForm').onsubmit=async e=>{e.preventDefault();await saveAll('Đã lưu hiệu chỉnh cảm biến')};$('eggType').onchange=e=>{const p=presets[e.target.value];if(p){setv('totalDays',p.days);setv('targetHumidity',p.humidity)}};$('endBatch').onclick=async()=>{if(await confirmBox('Kết thúc mẻ ấp','Dừng lịch đảo và đánh dấu mẻ đã kết thúc.','Kết thúc')){state.config.batchRunning=false;if(state.apiOnline)try{await post('/api/batch',{action:'end'})}catch{}saveLocal();fill();toast('Đã kết thúc mẻ ấp.')}};$('resetBatch').onclick=()=>{const keep={deviceName:state.config.deviceName,wifiSsid:state.config.wifiSsid};state.config={...state.config,...defaults,...keep};fill();toast('Đã khôi phục giá trị mẻ ấp.','warn')};$('deviceSelector').onchange=e=>loadDeviceById(e.target.value);$('scanWifi').onclick=async()=>{const s=$('wifiSsid');s.innerHTML='<option>Đang quét…</option>';try{const d=state.apiOnline?await api('/api/wifi/scan',{},10000):{networks:[{ssid:'Wi-Fi gia đình',rssi:-42},{ssid:'Xuong_Co_Khi',rssi:-58}]};s.innerHTML='<option value="">Chọn mạng Wi-Fi</option>'+d.networks.map(x=>`<option value="${esc(x.ssid)}">${esc(x.ssid)} · ${x.rssi} dBm</option>`).join('');if(state.config.wifiSsid)s.value=state.config.wifiSsid}catch{s.innerHTML='<option value="">Không quét được mạng</option>';toast('Không thể quét Wi-Fi. Có thể nhập SSID thủ công.','warn')}};document.querySelectorAll('[data-show]').forEach(b=>b.onclick=()=>{const i=$(b.dataset.show);i.type=i.type==='password'?'text':'password';b.textContent=i.type==='password'?'Hiện':'Ẩn'});$('enableSetupAp').onclick=async()=>{try{if(state.apiOnline){await post('/api/setup-ap',{minutes:10});toast('Đã bật trang cấu hình ban đầu.');setTimeout(()=>location.href='/setup',650)}else toast('Bản xem trước: đường dẫn /setup sẽ mở trang cấu hình Wi-Fi.')}catch{toast('Không bật được điểm cài đặt.','warn')}};$('startTune').onclick=async()=>{if(state.config.batchRunning)return toast('Không chạy Auto Tune khi đang có mẻ ấp.','error');if(state.apiOnline){try{const d=await post('/api/autotune',{action:'start',target:state.config.targetTemp});renderTune(d.autotune||{running:true,progress:0})}catch{toast('Không thể bắt đầu Auto Tune.','error')}}else localTune()};$('stopTune').onclick=async()=>{clearInterval(state.tune.localTimer);if(state.apiOnline)try{await post('/api/autotune',{action:'stop'})}catch{}renderTune({running:false,progress:0,result:null});toast('Đã dừng Auto Tune.','warn')};$('applyTune').onclick=()=>{const r=state.tune.result;if(!r)return;setv('kp',r.kp);setv('ki',r.ki);setv('kd',r.kd);state.config.kp=Number(r.kp);state.config.ki=Number(r.ki);state.config.kd=Number(r.kd);toast('Đã đưa kết quả vào form PID. Hãy nhấn lưu.')};$('unlockTest').onclick=async()=>{state.maintenanceUntil=Date.now()+300000;if(state.apiOnline)try{await post('/api/maintenance',{minutes:5})}catch{}$('maintenanceState').textContent='Đã mở 5 phút';$('maintenanceState').className='pill success';toast('Đã mở chế độ kiểm tra có giới hạn thời gian.')};$('startSystemTest').onclick=()=>{if(Date.now()>state.maintenanceUntil)return toast('Hãy mở chế độ kiểm tra trước.','warn');state.test={running:true,index:0,results:{}};runTestStep()};document.querySelectorAll('[data-answer]').forEach(b=>b.onclick=async()=>{const key=tests[state.test.index][0];if(key!=='sensor')await setOutput(key,false,true);state.test.results[state.test.index]=b.dataset.answer;state.test.index++;runTestStep()});$('outputList').onclick=e=>{const b=e.target.closest('[data-output]');if(b)setOutput(b.dataset.output,!state.status.outputs[b.dataset.output])};$('discoverDevices').onclick=discover;$('addManual').onclick=async()=>{const id=prompt('ID thiết bị, ví dụ MAP-A1B2:');if(!id)return;const ip=prompt('Địa chỉ IP của máy:','192.168.1.80')||'';mergeDevice({id:id.trim().toUpperCase(),name:'Máy ấp '+id.slice(-4),ip,online:false});renderDevice()};$('deviceList').onclick=e=>{const s=e.target.closest('[data-select]'),r=e.target.closest('[data-remove]');if(s)loadDeviceById(s.dataset.select);if(r){state.devices=state.devices.filter(x=>x.id!==r.dataset.remove);if(state.selectedId===r.dataset.remove)state.selectedId=state.hostDevice?.id||state.devices[0]?.id||'';saveDevices();renderDevice()}};$('exportConfig').onclick=()=>{const blob=new Blob([JSON.stringify(state.config,null,2)],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='cau-hinh-may-ap-'+new Date().toISOString().slice(0,10)+'.json';a.click();URL.revokeObjectURL(a.href)};$('importConfig').onchange=e=>{const f=e.target.files[0];if(!f)return;const rd=new FileReader();rd.onload=()=>{try{state.config={...defaults,...JSON.parse(rd.result)};saveLocal();fill();toast('Đã nhập cấu hình.')}catch{toast('Tệp JSON không hợp lệ.','error')}};rd.readAsText(f)};$('factoryReset').onclick=async()=>{if(!(await confirmBox('Khôi phục mặc định','Xóa cấu hình vận hành và Wi-Fi trên ESP32.','Xóa cấu hình')))return;state.config={...defaults};saveLocal();if(state.apiOnline)try{await post('/api/factory-reset',{confirm:'YES'},4000)}catch{}fill();toast('Đã khôi phục cấu hình mặc định.','warn')};$('mobileConn').onclick=()=>loadSelected();renderTest()}
async function init(){bind();enhanceBind();state.config=loadLocal();fill();await loadSelected(true);setInterval(poll,2500);setInterval(()=>{updateMaintenanceUi();if(Date.now()>state.maintenanceUntil&&$('maintenanceState').textContent!=='Đang khóa'){$('maintenanceState').textContent='Đang khóa';$('maintenanceState').className='pill neutral'}},1000)}
init();
// GitHub Pages is the source of the UI. When opened directly on GitHub it acts as
// an installable preview/PWA; when loaded by ESP32, API calls remain same-origin.
if(location.protocol==='https:'&&'serviceWorker'in navigator){
  navigator.serviceWorker.register(new URL('sw.js',MAYAP_ASSET_BASE).href).catch(()=>{});
}
if(!window.MAYAP_LOCAL_BRIDGE&&location.protocol==='https:'){
  setTimeout(()=>{try{toast('Web GitHub đang ở chế độ xem trước. Mở địa chỉ IP của ESP32 để điều khiển máy.','warn')}catch{}},700);
}
